import os
from flask import Flask, request
import pymysql

app = Flask(__name__)

def connect_to_cloudsql():
    # These variables are configured in app.yaml.
    cloud_sql_connection_name = os.getenv('CLOUD_SQL_CONNECTION_NAME')
    cloud_sql_user = os.getenv('CLOUD_SQL_USER')
    cloud_sql_password = os.getenv('CLOUD_SQL_PASSWORD')

    # When deployed to App Engine, the `unix_socket` argument is used to connect to
    # Cloud SQL using a Unix socket. When running locally, TCP is used instead.
    unix_socket = '/cloudsql/{}'.format(cloud_sql_connection_name)

    db = pymysql.connect(user=cloud_sql_user, password=cloud_sql_password, unix_socket=unix_socket, db='your-database')

    return db

@app.route('/search', methods=['GET'])
def search():
    db = connect_to_cloudsql()
    cursor = db.cursor()
    
    search_query = "SELECT * FROM your_table"

    filter_params = request.args
    if filter_params:
        filters = " WHERE " + " AND ".join([f"{k} = %s" for k in filter_params.keys()])
        search_query += filters

    cursor.execute(search_query, tuple(filter_params.values()))

    result = cursor.fetchall()

    return {'data': result}

if __name__ == '__main__':
    app.run(host='127.0.0.1', port=8080, debug=True)